import{c as t,cG as s,cb as d,c8 as i,cf as a,cT as e,ce as n}from"./chunks/framework.BlkIsu1j.js";const l=JSON.parse('{"title":"02. 数制与数据表示","description":"","frontmatter":{"title":"02. 数制与数据表示","outline":"deep","layout":"doc","prev":{"text":"01. 为什么要学 RISC-V 汇编","link":"/lang/assembly/01_why_riscv"},"next":{"text":"03. RISC-V 体系结构概览","link":"/lang/assembly/03_architecture"},"sidebar":true,"date":"2026-05-31T10:00:00.000Z"},"headers":[],"relativePath":"lang/assembly/02_number_systems.md","filePath":"lang/assembly/02_number_systems.md","lastUpdated":1780200373000}'),h={id:"frontmatter-title",tabindex:"-1"};const r=t({name:"lang/assembly/02_number_systems.md"},[["render",function(t,l,r,p,o,k){return s(),d("div",null,[i("h1",h,[a(e(t.$frontmatter.title)+" ",1),l[0]||(l[0]=i("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),l[1]||(l[1]=n('<p>汇编程序员必须对底层数据表示有精确的理解。寄存器中的位模式（bit pattern）本身没有类型——是加法指令把它当作整数，是浮点指令把它当作 IEEE 754 浮点数，是 load 指令把它从内存原样搬来。本章建立理解这些数值表示所需的基础。</p><h2 id="二进制与十六进制" tabindex="-1">二进制与十六进制 <a class="header-anchor" href="#二进制与十六进制" aria-label="Permalink to “二进制与十六进制”">​</a></h2><p><strong>二进制</strong>是 CPU 唯一识别的语言。数字电路中只有两个稳定状态（高电平/低电平），对应 1 和 0。数据的粒度从小到大：</p><table tabindex="0"><thead><tr><th>单位</th><th>位数</th><th>值范围（无符号）</th></tr></thead><tbody><tr><td>bit</td><td>1</td><td>0-1</td></tr><tr><td>nibble</td><td>4</td><td>0-15</td></tr><tr><td>byte</td><td>8</td><td>0-255</td></tr><tr><td>halfword</td><td>16</td><td>0-65535</td></tr><tr><td>word</td><td>32</td><td>0-约 43 亿</td></tr><tr><td>doubleword</td><td>64</td><td>0-约 1.8e19</td></tr></tbody></table><p>RISC-V 中：</p><ul><li>RV32 的 word = 32 位，doubleword = 64 位（基础指令操作 32 位）</li><li>RV64 的 word = 32 位，doubleword = 64 位（基础指令操作 64 位）</li><li>本教程以 <strong>RV64I</strong> 为基准，xl = 64 位</li></ul><p><strong>十六进制（hexadecimal）</strong> 是二进制的人肉缩写。一个 hex 位正好代表 4 个二进制位：</p><table tabindex="0"><thead><tr><th>Hex</th><th>Bin</th><th>Dec</th><th></th><th>Hex</th><th>Bin</th><th>Dec</th></tr></thead><tbody><tr><td>0</td><td>0000</td><td>0</td><td></td><td>8</td><td>1000</td><td>8</td></tr><tr><td>1</td><td>0001</td><td>1</td><td></td><td>9</td><td>1001</td><td>9</td></tr><tr><td>2</td><td>0010</td><td>2</td><td></td><td>A</td><td>1010</td><td>10</td></tr><tr><td>3</td><td>0011</td><td>3</td><td></td><td>B</td><td>1011</td><td>11</td></tr><tr><td>4</td><td>0100</td><td>4</td><td></td><td>C</td><td>1100</td><td>12</td></tr><tr><td>5</td><td>0101</td><td>5</td><td></td><td>D</td><td>1101</td><td>13</td></tr><tr><td>6</td><td>0110</td><td>6</td><td></td><td>E</td><td>1110</td><td>14</td></tr><tr><td>7</td><td>0111</td><td>7</td><td></td><td>F</td><td>1111</td><td>15</td></tr></tbody></table><p>你很快就会发现自己能用眼睛完成 hex-bin 转换。例如 <code>0x7A3</code> = <code>0111 1010 0011</code>。RISC-V 汇编中立即数和地址几乎总是 hex 书写，这是汇编程序员的书写语言。</p><p><strong>快速转换方法</strong>：</p><ul><li>Binary → Hex：从右往左每 4 位一组，查表转换</li><li>Hex → Binary：每位 hex 展开为 4 位二进制</li><li>Hex → Decimal：各数位乘 16 的幂再求和</li><li>Decimal → Hex：反复除 16 取余数，逆序排列</li></ul><p><strong>64 位数值实例</strong>。在 RV64I 中，整数操作默认 64 位（有 <code>addw</code> 等变体操作 32 位）：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>64-bit 最大值（无符号）: 0xFFFFFFFF_FFFFFFFF = 18,446,744,073,709,551,615</span></span>\n<span class="line"><span>64-bit 最大值（有符号）: 0x7FFF_FFFF_FFFF_FFFF =  9,223,372,036,854,775,807</span></span>\n<span class="line"><span>64-bit 最小值（有符号）: 0x8000_0000_0000_0000 = -9,223,372,036,854,775,808</span></span></code></pre></div><p>注意 RISC-V 汇编中常用下划线 <code>_</code> 分隔 hex 的每 4 位，这只是可读性写法，汇编器会忽略下划线。</p><h2 id="补码-有符号数的表示" tabindex="-1">补码：有符号数的表示 <a class="header-anchor" href="#补码-有符号数的表示" aria-label="Permalink to “补码：有符号数的表示”">​</a></h2><p>如何用只有 0 和 1 的电路表示负数？直观方案是最高位做符号位，其余位存绝对值——这叫<strong>原码</strong>。但它有两个严重缺陷：零有两种表示（+0 = 0x0000，-0 = 0x8000），且加减法需要额外电路处理符号。现代计算机选择了一种更巧妙的方案：<strong>补码（Two&#39;s Complement）</strong>。</p><p><strong>补码定义</strong>：$n$ 位补码中，最高位的权重是 $-2^{n-1}$（而不是 $2^{n-1}$），其余位权重照常。因此 $n$ 位补码范围是 $[-2^{n-1}, 2^{n-1}-1]$。</p><p><strong>计算负数</strong>：对正数 $x$，其相反数 $-x$ 的补码 = <code>~x + 1</code>（按位取反 + 1）。</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># RV64 中 -5 的补码计算</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x0000_0000_0000_0005</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">~</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0xFFFF_FFFF_FFFF_FFFA</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 按位取反</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0xFFFF_FFFF_FFFF_FFFB</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # = -5，验证：5 + (-5) = 0</span></span></code></pre></div><p><strong>补码的核心优势——加法共用硬件</strong>。这是 RISC-V 不区分 <code>add</code> 和 <code>addu</code> 的根本原因：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 同一段位模式，用同一套加法器硬件</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 无符号视角: 0xFFFF_FFFF_FFFF_FFFB = 18446744073709551611</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 有符号视角: 0xFFFF_FFFF_FFFF_FFFB = -5</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 无符号运算 5 + (-5):</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#  0x0000_0000_0000_0005 + 0xFFFF_FFFF_FFFF_FFFB = 0x0000_0000_0000_0000 (进位 1 丢弃)</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 有符号运算 5 + (-5):</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#  5 + (-5) = 0</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 同一套电路，同一段位模式，结果正确</span></span></code></pre></div><p>MIPS 有 <code>add</code>（溢出时 trap）和 <code>addu</code>（忽略溢出）两条指令，而 RISC-V 只有 <code>add</code>——更简洁。需要检测溢出时，RISC-V 通过分支指令比较操作数符号来间接判断。</p><p><strong>符号扩展</strong>。这是汇编中最重要的概念之一。当窄位宽的值被加载到宽位宽寄存器时，高位填充什么决定了语义：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 假设内存地址 0x1000 处有一个字节 0xFE（= -2 的 8 位补码）</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lb  x5, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x6)    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # byte load with sign-extension: x5 = 0xFFFF_FFFF_FFFF_FFFE (-2)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lbu x5, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x6)    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # byte load unsigned (zero-extension): x5 = 0x0000_0000_0000_00FE (254)</span></span></code></pre></div><p>RISC-V 的 <code>lb</code>/<code>lh</code>/<code>lw</code>（宽度后缀 + 无 <code>u</code>）做符号扩展，<code>lbu</code>/<code>lhu</code>/<code>lwu</code> 做零扩展。这不是语言细节——选错指令是最常见的 assembly bug 之一。</p><h2 id="大小端" tabindex="-1">大小端 <a class="header-anchor" href="#大小端" aria-label="Permalink to “大小端”">​</a></h2><p><strong>端序（endianness）</strong> 定义多字节值在内存中的字节排列顺序。RISC-V 采用小端序。</p><p><strong>小端（Little-Endian）</strong>：低字节在低地址。例如 <code>0x12345678</code> 作为 32-bit word 存储在地址 <code>0x1000</code>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>地址:    0x1000  0x1001  0x1002  0x1003</span></span>\n<span class="line"><span>内容:      0x78    0x56    0x34    0x12</span></span>\n<span class="line"><span>          (LSB)                       (MSB)</span></span></code></pre></div><p><strong>大端（Big-Endian）</strong>：高字节在低地址。同样 <code>0x12345678</code> 存储为：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>地址:    0x1000  0x1001  0x1002  0x1003</span></span>\n<span class="line"><span>内容:      0x12    0x34    0x56    0x78</span></span>\n<span class="line"><span>          (MSB)                       (LSB)</span></span></code></pre></div><p><strong>记忆方法</strong>：小端 = Little end（低位端）在前 → 低位字节在低地址。大端 = Big end（高位端）在前 → 高位字节在低地址。</p><p><strong>实际影响</strong>：</p><ul><li>RISC-V 默认小端（LE），BE 在规范中为可选——几乎所有 RISC-V 实现都是 LE</li><li>网络字节序是大端（TCP/IP 头），网络编程中常用 <code>htonl</code>/<code>ntohl</code> 转换</li><li>x86 是小端，ARM 可配置但主流也是小端</li><li>查看内存 dump 时注意端序——同样的 bytes，不同端序解释为不同的整数</li></ul><p><strong>端序与汇编的关系</strong>：当用 <code>ld</code> 指令从内存读取 8 字节到一个 64 位寄存器时，CPU 自动按小端序重排字节。汇编程序员通常不需要手动处理端序，但需要意识到它存在——尤其在调试内存 dump 或编写 binary 解析代码时。</p><h2 id="位运算基础" tabindex="-1">位运算基础 <a class="header-anchor" href="#位运算基础" aria-label="Permalink to “位运算基础”">​</a></h2><p>汇编层面操作的是位，位运算指令（AND/OR/XOR/移位）是 RISC-V 的基础。理解它们不只是为了写代码，更是为了读懂编译器生成的优化——编译器用位运算替代乘除法是常规操作。</p><p><strong>基本逻辑运算的真值表</strong>：</p><table tabindex="0"><thead><tr><th>A</th><th>B</th><th>AND</th><th>OR</th><th>XOR</th><th>NOT A</th></tr></thead><tbody><tr><td>0</td><td>0</td><td>0</td><td>0</td><td>0</td><td>1</td></tr><tr><td>0</td><td>1</td><td>0</td><td>1</td><td>1</td><td>1</td></tr><tr><td>1</td><td>0</td><td>0</td><td>1</td><td>1</td><td>0</td></tr><tr><td>1</td><td>1</td><td>1</td><td>1</td><td>0</td><td>0</td></tr></tbody></table><p><strong>移位的两种语义</strong>：</p><ul><li><strong>逻辑左移（SLL）</strong>：左移 n 位，低位填 0 → 等价于乘 $2^n$</li><li><strong>逻辑右移（SRL）</strong>：右移 n 位，高位填 0 → 无符号数除 $2^n$</li><li><strong>算术右移（SRA）</strong>：右移 n 位，高位填<strong>符号位</strong> → 有符号数除 $2^n$（向下取整！）</li></ul><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># RV64 移位示例</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">li   x5, -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # x5 = 0xFFFF_FFFF_FFFF_FFF0</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">srli x6, x5, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 逻辑右移 2: x6 = 0x3FFF_FFFF_FFFF_FFFC</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">srai x7, x5, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 算术右移 2: x7 = 0xFFFF_FFFF_FFFF_FFFC (-4)</span></span></code></pre></div><p>注意有符号数算术右移除 $2^n$ 时<strong>向下取整</strong>（向负无穷），而 C 语言的整数除法向零取整——这是汇编与高级语言之间需要注意的语义差异。</p><p><strong>常见位操作技巧</strong>：</p><table tabindex="0"><thead><tr><th>操作</th><th>位运算</th><th>RISC-V 指令序列</th></tr></thead><tbody><tr><td>清零第 k 位</td><td><code>x &amp; ~(1 &lt;&lt; k)</code></td><td><code>andi x, x, mask</code></td></tr><tr><td>置位第 k 位</td><td><code>x | (1 &lt;&lt; k)</code></td><td><code>ori x, x, mask</code></td></tr><tr><td>翻转第 k 位</td><td><code>x ^ (1 &lt;&lt; k)</code></td><td><code>xori x, x, mask</code></td></tr><tr><td>测试第 k 位</td><td><code>(x &gt;&gt; k) &amp; 1</code></td><td><code>srli + andi</code></td></tr><tr><td>乘 2^n</td><td><code>x &lt;&lt; n</code></td><td><code>slli x, x, n</code></td></tr><tr><td>除 2^n（无符号）</td><td><code>x &gt;&gt; n</code></td><td><code>srli x, x, n</code></td></tr><tr><td>提取低 n 位</td><td><code>x &amp; ((1&lt;&lt;n)-1)</code></td><td><code>andi x, x, mask</code></td></tr><tr><td>对齐至 2^n 边界</td><td><code>x &amp; ~(2^n - 1)</code></td><td><code>andi x, x, mask</code></td></tr></tbody></table><p>这些位操作在第 5-6 章会以 RISC-V 指令形式系统展开。</p><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to “本章要点”">​</a></h2><ul><li>十六进制是汇编程序员的书写语言，hex-bin 快速转换是基本功</li><li>补码让有/无符号加法共用同一套硬件——RISC-V 不区分 <code>add</code>/<code>addu</code> 的根本原因</li><li>符号扩展 vs 零扩展的选择（<code>lb</code> vs <code>lbu</code>）是最常见的 assembly bug</li><li>RISC-V 小端序，低字节在低地址，网络序为大端需要注意转换</li><li>AND/OR/XOR/移位直接对应 RISC-V 基础指令，编译器用位运算替代乘除法是常规优化</li></ul>',48))])}]]);export{l as __pageData,r as default};
